import { test, expect } from '@playwright/test';

test('checkout flow', async ({ page }) => {
  // 1. Click "Add to Cart" (getByRole)
  // 2. Fill "Quantity" to "3" (getByLabel)
  // 3. Check "Express Shipping" (getByLabel)
  // 4. Click "Checkout" (getByRole)
  // 5. Verify confirmation text
});

challenges.solution:
await page.getByRole('button', { name: 'Add to Cart' }).click();
await page.getByLabel('Quantity').fill('3');
await page.getByLabel('Express Shipping').check();
await page.getByRole('button', { name: 'Checkout' }).click();
await expect(page.locator('#confirmation')).toContainText('3 items (Express)');
